import type {Vocabulary} from "../../types"
import refKeyword from "./ref.js"
import typeKeyword, {JTDTypeError} from "./type.js"
import enumKeyword, {JTDEnumError} from "./enum.js"
import elements, {JTDElementsError} from "./elements.js"
import properties, {JTDPropertiesError} from "./properties.js"
import optionalProperties from "./optionalProperties.js"
import discriminator, {JTDDiscriminatorError} from "./discriminator.js"
import values, {JTDValuesError} from "./values.js"
import union from "./union.js"
import metadata from "./metadata.js"

const jtdVocabulary: Vocabulary = [
  "definitions",
  refKeyword,
  typeKeyword,
  enumKeyword,
  elements,
  properties,
  optionalProperties,
  discriminator,
  values,
  union,
  metadata,
  {keyword: "additionalProperties", schemaType: "boolean"},
  {keyword: "nullable", schemaType: "boolean"},
]

export default jtdVocabulary

export type JTDErrorObject =
  | JTDTypeError
  | JTDEnumError
  | JTDElementsError
  | JTDPropertiesError
  | JTDDiscriminatorError
  | JTDValuesError
